Here’s an example n8n workflow snippet for processing CVE data (like in SOC-CERT). This JSON represents a basic n8n workflow structure:

{
  "nodes": [
    {
      "name": "Fetch CVE Data",
      "type": "n8n-nodes-base.httpRequest",
      "parameters": {
        "url": "https://cve.circl.lu/api/last/",
        "method": "GET"
      }
    },
    {
      "name": "AI Scoring",
      "type": "n8n-nodes-base.function",
      "parameters": {
        "functionCode": "return items.map(item => ({
          ...item,
          aiScore: calculateRiskScore(item.cve)
        }));"
      }
    },
    {
      "name": "Send Slack Alert",
      "type": "n8n-nodes-base.slack",
      "parameters": {
        "channel": "#security-alerts",
        "text": "New CVE detected: {{ $('Fetch CVE Data').item.json.id }}"
      }
    }
  ],
  "connections": {
    "Fetch CVE Data": {
      "main": [[{"node": "AI Scoring", "type": "main", "index": 0}]]
    },
    "AI Scoring": {
      "main": [[{"node": "Send Slack Alert", "type": "main", "index": 0}]]
    }
  }
}
